<template>
  <q-page class="justify-evenly">
    <div>
      <any-render :config="customComponents" />
    </div>
    <div class="q-pa-md q-gutter-md">
      <template v-for="(row, rowIndex) in actionItems" :key="rowIndex">
        <div class="row">
          <template v-for="(actionItem, colIndex) in row" :key="colIndex">
            <div class="col">
              <q-card>
                <q-card-section>
                  <q-item-label header>
                    <q-icon :name="actionItem.icon" class="text-primary" />
                    <span class="text-primary">{{ actionItem.title }}</span>
                  </q-item-label>
                  <component :is="actionItem.component" />
                </q-card-section>
              </q-card>
            </div>
          </template>
        </div>
      </template>
    </div>

    <div class="q-pa-md q-gutter-md">
      <template v-bind:key="index+'sajsdsdfdlakds'" v-for="(form, index) in summaryItems">
        <div class="row">
          <template v-bind:key="index+'_'+index2+'sada3dsff23cui'" v-for="(item, index2) in form">
            <div class="col">
              <sum-item v-bind="item" />
            </div>

          </template>
        </div>
      </template>
    </div>
  </q-page>
</template>

<script lang="ts">
import { defineComponent } from 'vue';
import DashboardFormItem from '../components/DashboardFormItem.vue'
import DashBoardSumItem from '../components/DashboardSumItem.vue'
import AnyRender from '../components/AnyRender.vue';
import {default as ModelRegistry} from '../models'

import { default as ConfigRegistry} from '../components/dashboardRegistry'

const models = ModelRegistry.getInstance().getModels()

console.log(models['User'])

var formList = Object.keys(models).filter(key => models[key].META.includeInDashboard).map((key) => ({
  title: key,
  icon: models[key].META.icon,
  model: key,
  service: models[key].serviceType
}));

interface SummaryItem {
  title: string;
  model: string;
  icon: string;
  queryprops: {
    func: string;
    queryparams: {
      attribute: string;
      relation: string;
      refval: string;
    }[];
  };
  suffix: string;
}

interface ActionItem {
  title: string;
  icon: string;
  component: string;
}

export default defineComponent({
  name: 'DashboardPage',
  props: {
    summaryQueries: {
      type: Array<SummaryItem>(),
      default: () => ([]),
    },
    actionComponents: {
      type: Array<ActionItem>(),
      default: () => ([]),
    },
  },
  components: {
    'form-item': DashboardFormItem,
    'sum-item': DashBoardSumItem,
    'any-render': AnyRender
    // ...this.customComponents // Spread custom components into the components object
  },
  data() {
    return {
      rowSize: 4
    }
  },
  computed: {
    formItems() {
      return this.splitItem(formList)
    },
    summaryItems() {
      return this.splitItem(this.summaryQueries)
    },
    actionItems() {
      return this.splitItem(this.actionComponents)
    },
    customComponents() {
      return ConfigRegistry.getInstance().getConfig()
    }
    
  },
  methods: {
    splitItem(list) {
      for (let i = 0; i < list.length; i += this.rowSize) {
        var result = []
        const chunk = list.slice(i, i + this.rowSize);
        result.push(chunk);
        return result
      }
    }
  }
});
</script>
